import datetimeimport uuidfrom typing import Optionalfrom pgvector.sqlalchemy import VECTORfrom sqlalchemy import TIMESTAMP, ARRAY, VARCHAR, TEXT, INTEGER, UUIDfrom sqlalchemy.orm import Mapped, mapped_columnfrom database.entity.BaseModel import BaseModelclass PlatformCofounderNeedModel(BaseModel):    __tablename__ = 'platform_cofounder_need'    id: Mapped[uuid.UUID] = mapped_column(UUID, primary_key=True)    user_id: Mapped[uuid.UUID] = mapped_column(UUID)    title: Mapped[str] = mapped_column(VARCHAR(200))    description: Mapped[str] = mapped_column(TEXT)    role_wanted: Mapped[Optional[str]] = mapped_column(VARCHAR(20))    work_type: Mapped[Optional[str]] = mapped_column(VARCHAR(20))    skill_reqs: Mapped[Optional[list]] = mapped_column(ARRAY(TEXT))    industry: Mapped[Optional[str]] = mapped_column(VARCHAR(50))    city_reqs: Mapped[Optional[list]] = mapped_column(ARRAY(TEXT))    equity_range: Mapped[Optional[str]] = mapped_column(VARCHAR(50))    vesting: Mapped[Optional[str]] = mapped_column(VARCHAR(100))    embedding: Mapped[Optional[list]] = mapped_column(VECTOR)    status: Mapped[Optional[str]] = mapped_column(VARCHAR(20), comment="""active/paused/filled""")    view_count: Mapped[Optional[int]] = mapped_column(INTEGER)    created_at: Mapped[datetime.datetime] = mapped_column(TIMESTAMP)    expired_at: Mapped[datetime.datetime] = mapped_column(TIMESTAMP)    embedding_update_at: Mapped[Optional[datetime.datetime]] = mapped_column(TIMESTAMP)    update_at: Mapped[datetime.datetime] = mapped_column(TIMESTAMP)    match_update_at: Mapped[Optional[datetime.datetime]] = mapped_column(TIMESTAMP)